func archiveSlice(items []publicrender.ArchiveItem, start, end int) []publicrender.ArchiveItem {
	if start < 0 {
		start = 0
	}
	if end > len(items) {
		end = len(items)
	}
	if start >= len(items) || end <= start {
		return nil
	}
	return items[start:end]
}

func ogType(value string) string {
	if strings.TrimSpace(value) == "" {
		return "website"
	}
	return value
}

func termLabels(items []publicrender.TermView) string {
	labels := make([]string, 0, len(items))
	for _, item := range items {
		label := item.Label
		if item.Taxonomy != "" {
			label = item.Taxonomy + ": " + label
		}
		labels = append(labels, label)
	}
	return strings.Join(labels, " | ")
}

